import numpy as np

class RiskAnalyzer:
    """
    Comprehensive risk analysis for investment returns.
    """

    def __init__(self, returns, risk_free_rate=0.02):
        self.returns = np.array(returns)
        self.rf = risk_free_rate

    def volatility(self):
        """Annualized volatility."""
        return np.std(self.returns, ddof=1) * np.sqrt(252)

    def downside_deviation(self):
        """Annualized downside deviation."""
        below_zero = self.returns < 0
        if not np.any(below_zero):
            return 0.0
        squared_dev = np.sum(self.returns[below_zero] ** 2)
        return np.sqrt(squared_dev / (len(self.returns) - 1)) * np.sqrt(252)

    def max_drawdown(self):
        """Maximum drawdown."""
        cum_returns = np.cumprod(1 + self.returns)
        running_max = np.maximum.accumulate(cum_returns)
        drawdowns = (cum_returns - running_max) / running_max
        return np.min(drawdowns)

    def sharpe_ratio(self):
        """Sharpe ratio."""
        annual_ret = np.mean(self.returns) * 252
        vol = self.volatility()
        if vol == 0:
            return np.inf if annual_ret > self.rf else -np.inf
        return (annual_ret - self.rf) / vol

    def sortino_ratio(self):
        """Sortino ratio."""
        annual_ret = np.mean(self.returns) * 252
        down_dev = self.downside_deviation()
        if down_dev == 0:
            return np.inf if annual_ret > self.rf else -np.inf
        return (annual_ret - self.rf) / down_dev

    def calmar_ratio(self):
        """Calmar ratio."""
        annual_ret = np.mean(self.returns) * 252
        max_dd = abs(self.max_drawdown())
        if max_dd == 0:
            return np.inf if annual_ret > 0 else -np.inf
        return annual_ret / max_dd

    def summary(self):
        """Complete risk summary."""
        return {
            'Annual Return': np.mean(self.returns) * 252,
            'Volatility': self.volatility(),
            'Downside Dev': self.downside_deviation(),
            'Max Drawdown': self.max_drawdown(),
            'Sharpe': self.sharpe_ratio(),
            'Sortino': self.sortino_ratio(),
            'Calmar': self.calmar_ratio()
        }

def compare_strategies(returns_dict, risk_free_rate=0.02):
    """
    Compare multiple strategies.
    """
    comparison = {}
    for name, returns in returns_dict.items():
        analyzer = RiskAnalyzer(returns, risk_free_rate)
        comparison[name] = analyzer.summary()
    return comparison

# Test
np.random.seed(42)

strategies = {
    'Conservative': np.random.normal(0.0002, 0.008, 252),
    'Balanced': np.random.normal(0.0004, 0.012, 252),
    'Aggressive': np.random.normal(0.0006, 0.020, 252)
}

comparison = compare_strategies(strategies)
print('Strategy Comparison:')
print('=' * 60)
for strategy, metrics in comparison.items():
    print(f"\n{strategy}:")
    for metric, value in metrics.items():
        if isinstance(value, float):
            print(f"  {metric}: {value:.4f}")
